mapper.select:
SELECT o.id, o.order_no, u.nickname AS userName, o.total_amount, o.status, o.create_time, o.pay_time
FROM orders o
LEFT JOIN user u ON o.user_id = u.id


        AND o.order_no = #{orderNo}


        AND u.phone LIKE CONCAT('%', #{userPhone}, '%')


        AND o.status = #{status}


        AND DATE(o.create_time) >= #{beginTime}


        AND DATE(o.create_time) <= #{endTime}


ORDER BY o.create_time DESC
